B.acD=new A.ad("Metal Hangers",B.Sb)
B.TY=s(["Any laundry left in the washing machine from the previous shift should be taken out and hung on clothes lines.","Any dry clothes on clothes lines should be put away.","Dirty bathroom towels, dry mops, and dishroom/cutting gloves should be started as a load (these can also go in the end-of-shift load with table-wiping towels)."],t.s)
B.acv=new A.ad("Laundry",B.TY)
