B.acQ=new A.ad("Broken Glass",B.OJ)
B.Sr=s(["When and where do we use wet floor signs?","How do we clean up spills of any kind?","Make sure everyone understands that spills need to be cleaned up immediately.","Why should we clean up puddles in dishroom/scullery?"],t.s)
B.abo=new A.ad("Wet Floors",B.Sr)
