B.Qs=s(["The pulpers turn waste into pulp, which is then used to fertilize BYU Campus.","Do not reach into the pulper unless you have turned off the Disconnect Switch."],t.s)
B.ad1=new A.ad("Safety",B.Qs)
B.R0=s(["Banana peels","Watermelon rinds","Pineapple tops","Excessive rice and quinoa","Eggshells","Bones","Grease/oils","Wooden sticks","Styrofoam","Metal","Plastic","Paper dishes","Wrappers"],t.s)
B.acM=new A.ad("These Items Cannot Go in the Pulper",B.R0)
B.ON=s(["Make sure the pulper is filled and turned on, with the lid closed.","Check whether the Emergency Stop is engaged.","If not running, drain, refill, insert cardboard and run again.",'If the "Overflow" light is flashing, spray out the back chute of the Mother pulper. Ensure that the sensors of the Mother pulper are clear and that the laser is properly aligned.'],t.s)
B.ac1=new A.ad("If the Pulper Isn't Working",B.ON)
B.O8=s(["Each shift a cardboard box should be broken down and run through the dishroom and scullery pulpers.","Sunday Dinner Dishroom cleans the pulpers at the end of the day."],t.s)
B.acB=new A.ad("Reminders",B.O8)
